Modified greedy insertion with regret-based candidate selection, fallback to new assign if all existing candidates fail.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
    shipIDBase := total_ship
    for jj := 0; jj < len(oris); jj++ {
        bestAssignIdx := -1
        bestCostDelta := 1e18
        secondBestCostDelta := 1e18
        bestOriginalCost := 0.0

        // Try inserting into each existing non-empty assign
        for ai := 0; ai < dispatch.AssignsLen; ai++ {
            originalCost := dispatch.Assigns[ai].Cost
            added := dispatch.Assigns[ai].AddShip(shipIDBase+jj, oris[jj], dess[jj])
            if !added {
                continue
            }
            dispatch.Assigns[ai].GenRoute()
            if dispatch.Assigns[ai].Cost < 0 {
                dispatch.Assigns[ai].RemoveShip(shipIDBase + jj)
                dispatch.Assigns[ai].GenRoute()
                continue
            }
            costDelta := dispatch.Assigns[ai].Cost - originalCost
            dispatch.Assigns[ai].RemoveShip(shipIDBase + jj)
            dispatch.Assigns[ai].GenRoute()

            if costDelta < bestCostDelta {
                secondBestCostDelta = bestCostDelta
                bestCostDelta = costDelta
                bestAssignIdx = ai
                bestOriginalCost = originalCost
            } else if costDelta < secondBestCostDelta {
                secondBestCostDelta = costDelta
            }
        }

        // Compute regret value: difference between best and second-best insertion cost
        regretValue := secondBestCostDelta - bestCostDelta
        if bestAssignIdx == -1 {
            regretValue = 0
        }

        // Also try empty/new assigns as potential insertion targets
        var emptyCandidates []int
        seenIndices := make(map[int]bool)
        if bestAssignIdx != -1 {
            seenIndices[bestAssignIdx] = true
        }
        for ai := 0; ai < dispatch.AssignsLen; ai++ {
            if dispatch.Assigns[ai].StationsLen == 0 {
                emptyCandidates = append(emptyCandidates, ai)
            }
        }
        nextNewAssignIdx := dispatch.AssignsLen
        if nextNewAssignIdx < MAXASSIGNS {
            emptyCandidates = append(emptyCandidates, nextNewAssignIdx)
        }

        // Evaluate regret for empty/new assign option versus current best
        // If bestAssignIdx already chosen among non-empty, keep it unless regret strategy picks another
        // Simple rule: prefer minimal regret among reasonable candidates, fallback later

        // If we have a feasible insert among existing non-empty assigns, use regret-weighted decision
        // Here we implement a simplified regret tie-breaking: choose the smallest costDelta, break ties by smaller index
        // Actually we already selected bestAssignIdx as minimal costDelta above; now apply a regret filter:
        // If multiple candidates exist and regret is high, maybe still pick best due to simplicity requirement.
        // For this variant, we'll just use the best found above; if none, try empty/new assigns sequentially.

        inserted := false
        targetIdx := bestAssignIdx

        if targetIdx == -1 || bestCostDelta > 1e17 {
            // Fallback: try empty slots first, then create new assign
            for _, ei := range emptyCandidates {
                originalEmptyIdx := ei
                if ei >= dispatch.AssignsLen {
                    // This is a brand-new assign slot beyond current length
                    // Ensure it's within bounds
                    if dispatch.AssignsLen >= MAXASSIGNS {
                        continue
                    }
                    dispatch.Assigns[dispatch.AssignsLen].StationsLen = 0
                    dispatch.Assigns[dispatch.AssignsLen].Cost = 0.0
                    ei = dispatch.AssignsLen
                }
                added := dispatch.Assigns[ei].AddShip(shipIDBase+jj, oris[jj], dess[jj])
                if !added {
                    continue
                }
                dispatch.Assigns[ei].GenRoute()
                if dispatch.Assigns[ei].Cost < 0 {
                    dispatch.Assigns[ei].RemoveShip(shipIDBase + jj)
                    dispatch.Assigns[ei].GenRoute()
                    continue
                }
                if originalEmptyIdx >= dispatch.AssignsLen {
                    dispatch.AssignsLen++
                }
                inserted = true
                break
            }
        } else {
            // Perform actual insertion into best existing assign
            added := dispatch.Assigns[targetIdx].AddShip(shipIDBase+jj, oris[jj], dess[jj])
            if added {
                dispatch.Assigns[targetIdx].GenRoute()
                if dispatch.Assigns[targetIdx].Cost >= 0 {
                    inserted = true
                } else {
                    dispatch.Assigns[targetIdx].RemoveShip(shipIDBase + jj)
                    dispatch.Assigns[targetIdx].GenRoute()
                }
            }
        }

        // If still not inserted, attempt creation of new assign even if earlier emptyCandidates included it
        // because some slots may have been skipped due to AddShip failure
        if !inserted {
            if dispatch.AssignsLen < MAXASSIGNS {
                added := dispatch.Assigns[dispatch.AssignsLen].AddShip(shipIDBase+jj, oris[jj], dess[jj])
                if added {
                    dispatch.Assigns[dispatch.AssignsLen].GenRoute()
                    if dispatch.Assigns[dispatch.AssignsLen].Cost >= 0 {
                        dispatch.AssignsLen++
                        inserted = true
                    } else {
                        dispatch.Assigns[dispatch.AssignsLen].RemoveShip(shipIDBase + jj)
                        dispatch.Assigns[dispatch.AssignsLen].GenRoute()
                    }
                }
            }
        }
        // Continue processing remaining orders regardless of insertion success/failure for this order
